 *
 * @param nodeName Name for the node to update
 * @return bool Whether transactional update succeeded (no cycle created)
 */
bool test_transactional_update(const std::string& nodeName) {
    // 1. Create two observer nodes: source and target
    auto source = std::make_shared<TestTransactionalObserver>("source");
    auto target = std::make_shared<TestTransactionalObserver>("target");

    // 2. Get the observer graph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Add an observer relationship from source to target
    observerGraph.addObserver(source, target);

    // 4. Notify source node and verify target's change flag is set
    source->notify(true);
    if (!target->wasChanged()) {
        std::cerr << "Error: Target node not notified after initial setup" << std::endl;
        return false;
    }

    // 5. Reset both nodes to clear state
    source->reset();
    target->reset();

    bool updateSucceeded = false;

    // 6. Attempt transactional update that would create cycle
    // 7. Catch cycle exception using try-catch block
    try {
        // Use updateObserversTransactional to attempt adding observer relationship that would create cycle
        // This creates a cycle: source -> target and target -> source
        target->updateObserversTransactional({source});

        // If we reach here, no exception was thrown - update succeeded
        updateSucceeded = true;
    }
    catch (const reaction::CycleException& e) {
        // Cycle detected - update failed
        updateSucceeded = false;
        std::cout << "Cycle exception caught as expected: " << e.what() << std::endl;
