    // This verifies original relationship is preserved
    source->notify(true);
    if (!target->wasChanged()) {
        std::cerr << "Error: Target node not notified after cycle attempt" << std::endl;
        return false;
    }

    // 9. Return whether transactional update succeeded
    return updateSucceeded;
}

