```cpp
#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

struct BatchExecuteResult {
    int recomputeCountBeforeBatch;
    int recomputeCountAfterBatch;
    int finalValue;
};

BatchExecuteResult test_batch_execute_update(int baseValue, int deltaA, int deltaB) {
    using namespace reaction;

    // 1. Create reactive variable varA with initial value baseValue
    auto varA = reaction::var(baseValue);

    // 2. Create reactive variable varB with initial value 0
    auto varB = reaction::var(0);

    // 3. Create reactive variable recomputeCount to track calculation recomputations
    auto recomputeCount = reaction::var(0);

    // 4. Create calculation that depends on varA and varB and returns their sum
    auto calc = reaction::calc([&]() -> int {
        // Increment recomputeCount each time calculation runs
        recomputeCount.value(recomputeCount.get() + 1);

        // Return sum of varA and varB
        return varA.get() + varB.get();
    });

    // 5. Record recompute count before batch execution
    int recomputeCountBefore = recomputeCount.get();

    // 6. Execute batch updates using reaction::batchExecute
    reaction::batchExecute([&]() {
        // Update varA and varB within batch
        varA.value(baseValue + deltaA);
        varB.value(deltaB);
    });

    // 7. Record recompute count after batch execution
    int recomputeCountAfter = recomputeCount.get();

    // 8. Get final value of calculation
    int finalValue = calc.get();

    // 9. Return BatchExecuteResult with all recorded values
    return BatchExecuteResult{
        .recomputeCountBeforeBatch = recomputeCountBefore,
        .recomputeCountAfterBatch = recomputeCountAfter,
        .finalValue = finalValue
    };
}

}  // namespace test_reaction
```

