BatchLifecycleResult test_batch_manual_lifecycle(int initialValue, int updatedValue) {
    // 1. Create reactive variable using reaction::var with initial value
    auto reactiveVar = reaction::var(initialValue);

    // 2. Create reactive variable for recompute count using reaction::var initialized to 0
    auto recomputeCount = reaction::var(0);

    // 3. Create calculation using reaction::calc that depends on the first variable and increments the recompute count
    auto calculation = reaction::calc([&]() {
        // Access the reactive variable to establish dependency
        int value = reactiveVar();
        // Increment recompute count
        recomputeCount.value(recomputeCount() + 1);
        return value; // Return the value to ensure the calculation is evaluated
    });

    // 4. Create Batch object with lambda that updates the first variable
    auto batch = reaction::batch([&]() {
        reactiveVar.value(updatedValue);
    });

    // 5. Use isClosed() method to check if batch is closed initially
    bool closedInitially = batch.isClosed();

    // 6. Call execute() method on the batch
    batch.execute();

    // 7. Access the calculation value to trigger evaluation and record recompute count
    int recomputeCountAfterExecute = recomputeCount();

    // 8. Call close() method on the batch
    batch.close();

    // 9. Use isClosed() method to verify batch is closed after close
    bool closedAfterClose = batch.isClosed();

    // 10. Ensure calculation is evaluated by accessing its value
    // This is already done in step 7, but we'll do it again to be safe
    calculation();

    // 11. Return BatchLifecycleResult struct with all required values
    return BatchLifecycleResult{
        .closedInitially = closedInitially,
        .closedAfterClose = closedAfterClose,
        .recomputeCountAfterExecute = recomputeCountAfterExecute
    };
}

