    auto logical_not_expr = !bool_var;

    // 4. Create reactive integer variable and build bitwise NOT expression
    auto int_var = var(0xFF); // Example value: 255
    auto bitwise_not_expr = ~int_var;

    // 5. Use get() method to retrieve initial values of expressions
